mapper.select:
SELECT a.*,
u.real_name   AS student_name,
stu.student_number,
c.class_name,
t.real_name    AS teacher_name
FROM attendance a
LEFT JOIN student stu ON a.student_id = stu.id
LEFT JOIN sys_user u ON stu.id = u.id
LEFT JOIN class c ON stu.class_id = c.id
LEFT JOIN sys_user t ON a.teacher_id = t.id
WHERE 1=1

    AND c.id = #{classId}


    AND a.attendance_date >= #{startDate}


    AND a.attendance_date <= #{endDate}


    AND a.status = #{status}


    AND u.real_name LIKE CONCAT('%', #{studentName}, '%')



    AND a.student_id = #{studentId}


    AND a.student_id IN

        #{id}


ORDER BY a.attendance_date DESC, a.id DESC

SELECT *
FROM attendance
WHERE student_id = #{studentId}
  AND attendance_date = #{date}

mapper.update:
UPDATE attendance
SET status=#{status},
    remark=#{remark},
    teacher_id=#{teacherId}
WHERE id = #{id}
